import{_ as i,o as t,c as o,ag as n}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Multi-monitor Support in RDP","description":"Imported note from Hardening Consulting","frontmatter":{"title":"Multi-monitor Support in RDP","description":"Imported note from Hardening Consulting"},"headers":[],"relativePath":"misc/inbox-imports/hardening-consulting-multi-monitor-rdp.md","filePath":"misc/inbox-imports/hardening-consulting-multi-monitor-rdp.md"}'),a={name:"misc/inbox-imports/hardening-consulting-multi-monitor-rdp.md"};function r(l,e,s,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="multi-monitor-support-in-rdp" tabindex="-1">Multi-monitor Support in RDP <a class="header-anchor" href="#multi-monitor-support-in-rdp" aria-label="Permalink to &quot;Multi-monitor Support in RDP&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://www.hardening-consulting.com/en/posts/20170302-multi-monitor-rdp.html" target="_blank" rel="noreferrer">https://www.hardening-consulting.com/en/posts/20170302-multi-monitor-rdp.html</a></li><li>Author: Hardening Consulting (author byline not explicitly listed on the page)</li><li>Imported: 2026-04-20</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>This note captures a technical write-up about implementing multi-monitor support in RDP, with lessons learned from integrating FreeRDP-based components and testing interoperability with Microsoft&#39;s <code>mstsc</code>.</p><h3 id="testing-setup-used-by-the-author" tabindex="-1">Testing setup used by the author <a class="header-anchor" href="#testing-setup-used-by-the-author" aria-label="Permalink to &quot;Testing setup used by the author&quot;">​</a></h3><ul><li>Baseline validation with two physical screens and <code>xfreerdp /v:myserver /multimon /f</code>.</li><li>For virtualized Windows client testing, QEMU/KVM with SPICE and multiple QXL video cards was used.</li><li><code>remote-viewer spice://127.0.0.1:5902</code> was preferred over virt-manager display because it exposes one window per monitor.</li></ul><h3 id="protocol-level-behavior-observed" tabindex="-1">Protocol-level behavior observed <a class="header-anchor" href="#protocol-level-behavior-observed" aria-label="Permalink to &quot;Protocol-level behavior observed&quot;">​</a></h3><ul><li>Client monitor layout is sent early during connection (GCC / MCS connect request), including monitor coordinates and dimensions.</li><li>Server can respond with a Server Monitor Layout PDU; in practice this appears required for <code>mstsc</code> multi-monitor behavior.</li><li>The write-up notes that <code>mstsc</code> behavior may diverge from strict spec expectations, especially around monitor coordinate origins.</li></ul><h3 id="backend-and-client-implementation-notes" tabindex="-1">Backend and client implementation notes <a class="header-anchor" href="#backend-and-client-implementation-notes" aria-label="Permalink to &quot;Backend and client implementation notes&quot;">​</a></h3><ul><li>Existing backend assumptions of a single monitor required significant refactoring.</li><li>X11 and Qt backends were already suitable for multi-monitor workflows once API interactions were corrected.</li><li>Practical fixes included: <ul><li>handling monitor sets with negative coordinates;</li><li>renegotiating dimensions correctly;</li><li>adjusting window placement/fullscreen logic.</li></ul></li></ul><h3 id="egfx-specific-complexity" tabindex="-1">egfx-specific complexity <a class="header-anchor" href="#egfx-specific-complexity" aria-label="Permalink to &quot;egfx-specific complexity&quot;">​</a></h3><ul><li>Issues appeared when egfx was used, even when planar/RemoteFX modes looked correct.</li><li>The author compared behavior with official Windows server behavior and observed: <ul><li>use of <code>RDPGFX_RESET_GRAPHICS_PDU</code> for resizing and monitor layout reset;</li><li>per-monitor <code>RDPGFX_CREATE_SURFACE_PDU</code> usage instead of one large surface.</li></ul></li><li>Rendering logic was reworked to split damage per monitor and rebase coordinates per surface.</li><li>Additional complexity came from monitor-count limiting and shadowing sessions.</li></ul><h3 id="final-implementation-trade-off" tabindex="-1">Final implementation trade-off <a class="header-anchor" href="#final-implementation-trade-off" aria-label="Permalink to &quot;Final implementation trade-off&quot;">​</a></h3><ul><li>H264 was disabled in the multi-monitor path due to per-surface codec context complexity.</li><li>Main lesson: proprietary interoperability introduces hidden complexity and schedule risk.</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Multi-monitor RDP support is strongly shaped by real client behavior, not only protocol specs.</li><li><code>mstsc</code> interoperability can require optional PDUs in practice and tolerate coordinate edge cases.</li><li>egfx multi-monitor support often needs per-monitor surface and repaint pipelines.</li><li>Plan extra implementation and testing buffer for proprietary-client compatibility work.</li></ul>',17)])])}const h=i(a,[["render",r]]);export{m as __pageData,h as default};
